{
  "type": "FLIP_CARD",
  "lessonText": "Understanding cough types helps in identifying underlying conditions.",
  "data": {
    "cards": [
      {
        "front": "Dry Cough",
        "back": "A non-productive cough that does not produce mucus. Often associated with irritation or allergies.",
        "icon": "cough",
        "imageUrl": "https://example.com/dry_cough.jpg"
      },
      {
        "front": "Wet Cough",
        "back": "A productive cough that brings up mucus. Commonly indicates infections like bronchitis or pneumonia.",
        "icon": "mucus",
        "imageUrl": "https://example.com/wet_cough.jpg"
      },
      {
        "front": "Chronic Cough",
        "back": "A cough lasting more than eight weeks. Can signal serious conditions like asthma or GERD.",
        "icon": "chronic",
        "imageUrl": "https://example.com/chronic_cough.jpg"
      },
      {
        "front": "Barking Cough",
        "back": "A harsh, dry cough that sounds like a seal. Often seen in croup or upper airway infections.",
        "icon": "bark",
        "imageUrl": "https://example.com/barking_cough.jpg"
      }
    ]
  }
}
